/*eslint-env node, mocha */

"use strict";

require("should");
var path = require('path');

var keyframes = require('../../');
var JiboKeyframeInfo = require("../../lib/jibo-keyframe-info");

describe('Keyframes layers should be evaluated properly in blink mode', function() {
	var blinkmode;
	var allProps;
	it('Blink mode test file should load', function () {
		blinkmode = keyframes.runtime.load(__dirname + "/fixtures/blink.keys", JiboKeyframeInfo);
	});

	it('Loaded file should have 4 layers', function() {
		blinkmode.layers.length.should.equal(4);
	});
	it('EvaluateAllLayers should run without failure', function() {
		allProps = keyframes.runtime.evaluateAllLayersFiltered(blinkmode, JiboKeyframeInfo, 0, ()=> {return true;});
	});
	it('The top level overlay rotation of 50 should be absent.', function() {
		allProps.Overlay.Rotate.should.equal(0);
	});
	it('Referenced overlay should be translated 10 by the top level Eye.', function() {
		// 15 = 5 from the referenced overlay and 10 from the top level eye
		allProps.Overlay.Translate.x.should.equal(15);
	});

});

describe('Keyframes layers should evaluate normally when not in blink mode', function() {
	var blinkmode;
	var allProps;
	it('EvaluateAllLayers should run without failure', function() {
		blinkmode = keyframes.runtime.load(__dirname + "/fixtures/blink.keys", JiboKeyframeInfo);
		// Disable the referenced eye layer
		blinkmode.layers[2].id = 'normal_non_ref_layer_id';
		allProps = keyframes.runtime.evaluateAllLayersFiltered(blinkmode, JiboKeyframeInfo, 0, ()=> {return true;});
	});
	it('The top level overlay rotation of 50 should be present.', function() {
		allProps.Overlay.Rotate.should.equal(50);
	});
	it('Referenced overlay should not be translated 10 by the top level Eye.', function() {
		// 50 from top level overlay plus 5 from the referenced overlay
		allProps.Overlay.Translate.x.should.equal(55);
	});

});

describe('Layer bounding (the validFrom, validUpto, and holdAfter parameters) should modify the evaluated frame properties', function() {
	var blinkmode;
	var fifteenProps;
	var zeroProps;

	it('There should be an eye and overlay property at timepoint 0.', function() {
		blinkmode = keyframes.runtime.load(__dirname + "/fixtures/blink.keys", JiboKeyframeInfo);
		zeroProps = keyframes.runtime.evaluateAllLayersFiltered(blinkmode, JiboKeyframeInfo, 0, ()=> {return true;});
		('Eye' in zeroProps).should.equal(true);
		('Overlay' in zeroProps).should.equal(true);
	});

	it('Layer bounding: there should be no properties at all in the evaluated layers after the validUpto point.', function() {
		for (let layer of blinkmode.layers) {
			layer.validFrom = 0;
			layer.validUpto = 10;
		}
		fifteenProps = keyframes.runtime.evaluateAllLayersFiltered(blinkmode, JiboKeyframeInfo, 15, ()=> {return true;});
		Object.keys(fifteenProps).length.should.equal(0);
	});

	it('Layer bounding: eye and overlay properties computed *after* the holdAfter point should equal those *at* the holdAfter point.', function() {
		var blinkfile = keyframes.runtime.load(__dirname + "/fixtures/blink.keys", JiboKeyframeInfo);
		for (let layer of blinkfile.layers) {
			layer.validFrom = 0;
			layer.holdAfter = 3;
		}
		let threeProps = keyframes.runtime.evaluateAllLayersFiltered(blinkfile, JiboKeyframeInfo, 3, ()=> {return true;});
		fifteenProps = keyframes.runtime.evaluateAllLayersFiltered(blinkfile, JiboKeyframeInfo, 15, ()=> {return true;});
		JSON.stringify(threeProps).should.equal(JSON.stringify(fifteenProps));
	});

});

